patch:
diff --git a/llvm/lib/IR/ConstantFold.cpp b/llvm/lib/IR/ConstantFold.cpp
index 72d627886fd0a..87a70391fbec4 100644
--- a/llvm/lib/IR/ConstantFold.cpp
+++ b/llvm/lib/IR/ConstantFold.cpp
@@ -17,6 +17,7 @@
 //===----------------------------------------------------------------------===//

 #include "llvm/IR/ConstantFold.h"
+#include "llvm/ADT/APInt.h"
 #include "llvm/ADT/APSInt.h"
 #include "llvm/ADT/SmallVector.h"
 #include "llvm/IR/Constants.h"
@@ -86,8 +87,14 @@ static Constant *FoldBitCast(Constant *V, Type *DestTy) {
         APFloat(DestTy->getScalarType()->getFltSemantics(), CI->getValue()));
   }

-  // Handle ConstantFP -> ConstantInt
+  // Handle ConstantFP -> Constant{Int, FP}
   if (ConstantFP *FP = dyn_cast<ConstantFP>(V)) {
+    // Handle half <-> bfloat
+    if (!isa<VectorType>(SrcTy) && DestTy->isFloatingPointTy()) {
+      APInt Val = FP->getValueAPF().bitcastToAPInt();
+      APFloat ResultFP(DestTy->getFltSemantics(), Val);
+      return ConstantFP::get(DestTy->getContext(), ResultFP);
+    }
     // Canonicalize scalar-to-vector bitcasts into vector-to-vector bitcasts
     // This allows for other simplifications (although some of them
     // can only be handled by Analysis/ConstantFolding.cpp).

tests.test_body:
define <2 x bfloat> @bfloat_to_half_vec() {
  %val = bitcast <2 x half> splat (half 0xH7C00) to <2 x bfloat>
  ret <2 x bfloat> %val
}

define <2 x half> @half_to_bfloat_vec() {
  %val = bitcast <2 x bfloat> splat (bfloat 0xR7C00) to <2 x half>
  ret <2 x half> %val
}

define half @recursive() {
  %first = bitcast bfloat 0xR7C00 to half
  %second = bitcast half %first to bfloat
  %third = bitcast bfloat %second to half
  ret half %third
}

define bfloat @bfloat_to_half() {
  %val = bitcast half 0xH7C00 to bfloat
  ret bfloat %val
}

define half @half_to_bfloat() {
  %val = bitcast bfloat 0xR7C00 to half
  ret half %val
}
